@pith_y.setter def pith_y(self, value: float): """Set the Pith Y coordinate.""" pass
@Property(bool) def is_fake_pith(self) -> bool: """Get whether this knot has a fake pith.""" pass
@is_fake_pith.setter def is_fake_pith(self, value: bool): """Set whether pith is fake.""" pass
@Property(str) def comment(self) -> str: """Get the knot comment.""" pass
@comment.setter def comment(self, value: str): """Set the knot comment.""" pass
